+// ─── Walking animation frames ───────────────────────────────────────
+// Each frame is a sprite string array representing the character with different leg positions
+// We define 4 frames per direction: up, down, left, right
+// For simplicity, reuse base sprite but alter legs pixels to simulate walking
+
+// Helper to clone and modify sprite lines
+function cloneSprite(sprite: string[]): string[] {
+  return sprite.map(line => line.slice());
+}
+
+// Modify legs for walking frames
+function createWalkFrames(baseSprite: string[]): string[][] {
+  // Assume sprite height >= 16 and legs at bottom 4 rows
+  // We'll create 4 frames with legs moving alternately
+  const frames: string[][] = [];
+  for (let f = 0; f < 4; f++) {
+    const frame = cloneSprite(baseSprite);
+    // Simple leg movement: alternate pixels in bottom rows
+    // We'll toggle some pixels in rows 12-15 to simulate stepping
+    // For example, shift leg pixels left/right or up/down
+    // This is a pixel-art style approximation
+    const legRows = [12, 13, 14, 15];
+    for (const r of legRows) {
+      let line = frame[r].split('');
+      for (let c = 0; c < line.length; c++) {
+        // Toggle leg pixels 'l' and 'r' for left/right leg
+        // We'll use 'l' and 'r' as placeholders for leg pixels
+        if (line[c] === 'l' || line[c] === 'r') {
+          // For frame 0 and 2 legs forward, 1 and 3 legs backward
+          if ((f % 4) === 0 || (f % 4) === 2) {
+            // Legs forward: 'l' -> 'L', 'r' -> 'R'
+            line[c] = line[c].toUpperCase();
+          } else {
+            // Legs backward: 'L' -> 'l', 'R' -> 'r'
+            line[c] = line[c].toLowerCase();
+          }
+        }
+      }
+      frame[r] = line.join('');
+    }
+    frames.push(frame);
+  }
+  return frames;
+}
+
+// We need to prepare 4 directions of walk frames per character type
+// For demonstration, we create a simple walk cycle by modifying the base sprite for each direction
+
+// We'll create a map: characterType -> direction -> frames[]
+const WALK_FRAMES: Record<CharacterType, Record<string, string[][]>> = {};
+
+// Directions
+const DIRECTIONS = ['down', 'left', 'right', 'up'];
+
+// For each character type, generate walk frames by direction
+for (const [charType, baseSprite] of Object.entries(CHAR_SPRITES) as [CharacterType, string[]][]) {
+  WALK_FRAMES[charType] = {};
+  for (const dir of DIRECTIONS) {
+    // For left and right, flip horizontally if needed
+    // We'll create base frames with legs marked as 'l' and 'r' for modification
+    // For simplicity, assume legs are at bottom rows and replace some pixels with 'l' and 'r'
+    // Clone base sprite and mark legs
+    const base = cloneSprite(baseSprite);
+    // Mark legs pixels: naive approach, mark last two columns bottom 4 rows as legs
+    for (let r = base.length - 4; r < base.length; r++) {
+      let line = base[r].split('');
+      // Mark left leg at col 3, right leg at col 6 if within bounds
+      if (line.length > 6) {
+        if (line[3] !== ' ' && line[3] !== '0') line[3] = 'l';
+        if (line[6] !== ' ' && line[6] !== '0') line[6] = 'r';
+      }
+      base[r] = line.join('');
+    }
+    // Create 4 walk frames with leg movement
+    let frames = createWalkFrames(base);
+    // For left direction, flip frames horizontally
+    if (dir === 'left') {
+      frames = frames.map(frame => frame.map(line => line.split('').reverse().join('')));
+    }
+    // For right direction, use as is
+    // For up and down, use as is (could add different leg patterns if desired)
+    WALK_FRAMES[charType][dir] = frames;
+  }
+}
+
+// Draw walking character with frame and direction
+export function drawWalkingCharacter(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  type: CharacterType,
+  frame: number,
+  direction: string,
+) {
+  const palette = PALETTE_MAP[type];
+  if (!palette) return;
+  const frames = WALK_FRAMES[type]?.[direction];
+  if (!frames) return;
+  const f = frame % frames.length;
+  const sprite = frames[f];
+  drawSpriteDef(ctx, sprite, palette, x, y, 2, direction === 'left');
+}
+
+// Override updateMovement to increment walk frame counter for smooth animation
+function updateMovementWithWalk(cs: CharState, bounds: { x: number; y: number; w: number; h: number }) {
+  const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist > 2) {
+    cs.moving = true;
+    cs.x += (dx / dist) * 0.4;
+    cs.y += (dy / dist) * 0.4;
+    cs.wf++;
+    cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
+  } else {
+    cs.moving = false;
+    cs.wf = 0;
+    cs.idle--;
+    if (cs.idle <= 0) {
+      const mx = bounds.w * 0.15, my = bounds.h * 0.2;
+      cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
+      cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
+      cs.idle = 150 + Math.random() * 300;
+    }
+  }
+}
+
+// Replace original updateMovement export with new function
+export { updateMovementWithWalk as updateMovement };
