+export function AgentsScene() {
+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+
+  useEffect(() => {
+    const canvas = canvasRef.current;
+    if (!canvas) return;
+    const ctx = canvas.getContext('2d');
+    if (!ctx) return;
+
+    const bounds = { x: 0, y: 0, w: canvas.width, h: canvas.height };
+
+    // Initialize char states for agents
+    agents.forEach(agent => getCS(agent.id, bounds.w / 2, bounds.h / 2));
+
+    const loop = startGameLoop((frame) => {
+      syncCanvasSize(canvas);
+      clearCanvas(ctx);
+      drawRoom(ctx, bounds);
+
+      agents.forEach(agent => {
+        const cs = getCS(agent.id, bounds.w / 2, bounds.h / 2);
+        updateMovement(cs, bounds);
+        // Draw walking character with walk frame and direction
+        const walkFrame = Math.floor(cs.wf / 6) % 4; // slower frame rate for walk cycle
+        drawWalkingCharacter(ctx, cs.x, cs.y, agent.tier, walkFrame, cs.dir);
+      });
+    });
+
+    return () => loop.cancel();
+  }, [agents]);
+
+  return <canvas ref={canvasRef} style={{ width: '100%', height: '100%' }} />;
+}
